from flask import Flask, send_from_directory
import os

app = Flask(__name__)

ALLOWED_DIRECTORY = os.path.abspath('uploads')

@app.route('/uploads/<path:filename>')
def serve_legacy_file(filename):
    file_path = os.path.join(ALLOWED_DIRECTORY, filename)
    if os.path.exists(file_path) and file_path.startswith(ALLOWED_DIRECTORY):
        return send_from_directory(ALLOWED_DIRECTORY, filename)
    else:
        return "File not found", 404